<body>
    <!-- Sidebar Overlay -->
    <div class="sidebar-overlay" id="sidebarOverlay"></div>

    <!-- Sidebar -->
    <aside class="sidebar" id="sidebar">
        <button class="sidebar-close" onclick="toggleSidebar()">
            <i class="fas fa-times"></i>
        </button>

        <div class="sidebar-header">
            <img src="{% static 'images/logo.png' %}" alt="Elite Wealth" class="sidebar-logo" onerror="this.style.display='none'" loading="eager">
            <div class="sidebar-brand">Elite Wealth Capital</div>
        </div>

        {% if user.is_authenticated %}
        <div class="sidebar-user">
            <div class="user-avatar">
                {% if user.profile_image %}
                    <img src="{{ user.profile_image.url }}" alt="{{ user.full_name }}">
                {% else %}
                    {{ user.full_name|slice:":1"|upper|default:"?" }}
                {% endif %}
            </div>
            <div class="user-name">{{ user.full_name|default:user.email }}</div>
            <div class="user-balance">${{ user.balance|floatformat:2|default:"0.00" }}</div>
            <small style="color: var(--text-muted);">Available Balance</small>
        </div>
        {% else %}
        <div class="sidebar-user">
            <div class="user-avatar">
                <i class="fas fa-user"></i>
            </div>
            <div class="user-name">Guest</div>
            <a href="{% url 'accounts:login' %}" class="btn-gold btn-sm" style="margin-top: 10px; padding: 8px 20px; font-size: 0.85rem;">
                <i class="fas fa-sign-in-alt me-1"></i>Login
            </a>
        </div>
        {% endif %}

        <nav class="sidebar-nav">
            <div class="nav-section">Main</div>
            {% if user.is_authenticated %}
            <a href="{% url 'dashboard:dashboard' %}" class="nav-item {% if request.resolver_match.url_name == 'dashboard' %}active{% endif %}">
                <i class="fas fa-home"></i> Dashboard
            </a>
            {% else %}
            <a href="/" class="nav-item">
                <i class="fas fa-home"></i> Home
            </a>
            {% endif %}

            <div class="nav-section">Finance</div>
            {% if user.is_authenticated %}
            <a href="{% url 'investments:deposit' %}" class="nav-item {% if request.resolver_match.url_name == 'deposit' %}active{% endif %}">
                <i class="fas fa-plus-circle"></i> Add Funds
            </a>
            {% endif %}
            <a href="{% url 'investments:plans' %}" class="nav-item {% if request.resolver_match.url_name == 'plans' %}active{% endif %}" style="background: linear-gradient(135deg, rgba(255,215,0,0.15), rgba(255,165,0,0.15)); border-left: 3px solid var(--gold);">
                <i class="fas fa-rocket" style="color: var(--gold);"></i> <strong style="color: var(--gold);">Buy Shares</strong>
            </a>
            {% if user.is_authenticated %}
            <a href="{% url 'investments:withdraw' %}" class="nav-item {% if request.resolver_match.url_name == 'withdraw' %}active{% endif %}">
                <i class="fas fa-minus-circle"></i> Withdraw
            </a>
            <a href="{% url 'dashboard:transactions' %}" class="nav-item {% if request.resolver_match.url_name == 'transactions' %}active{% endif %}">
                <i class="fas fa-exchange-alt"></i> Transactions
            </a>

            <div class="nav-section">Investments</div>
            <a href="{% url 'investments:my_investments' %}" class="nav-item {% if request.resolver_match.url_name == 'my_investments' %}active{% endif %}">
                <i class="fas fa-briefcase"></i> My Investments
            </a>

            <div class="nav-section">Services</div>
            <a href="{% url 'investments:loans' %}" class="nav-item {% if request.resolver_match.url_name == 'loans' %}active{% endif %}">
                <i class="fas fa-hand-holding-usd"></i> Loans
            </a>
            <a href="{% url 'investments:cards' %}" class="nav-item {% if request.resolver_match.url_name == 'cards' %}active{% endif %}">
                <i class="fas fa-credit-card"></i> Virtual Cards
            </a>
            <a href="{% url 'investments:agent' %}" class="nav-item {% if request.resolver_match.url_name == 'agent' %}active{% endif %}">
                <i class="fas fa-users"></i> Agent Program
            </a>
            {% endif %}

            <div class="nav-section">Support</div>
            <a href="javascript:void(0);" onclick="openLiveChat()" class="nav-item" style="background: rgba(0, 212, 170, 0.1); border-left: 3px solid var(--success);">
                <i class="fas fa-comments" style="color: var(--success);"></i> <span style="color: var(--success);">Live Chat</span>
            </a>
            <a href="{% url 'dashboard:contact' %}" class="nav-item {% if request.resolver_match.url_name == 'contact' %}active{% endif %}">
                <i class="fas fa-envelope"></i> Contact Us
            </a>
            <a href="{% url 'dashboard:faq' %}" class="nav-item {% if request.resolver_match.url_name == 'faq' %}active{% endif %}">
                <i class="fas fa-question-circle"></i> FAQ
            </a>

            {% if user.is_authenticated %}
            <div class="nav-section">Account</div>
            <a href="{% url 'dashboard:settings' %}" class="nav-item {% if request.resolver_match.url_name == 'settings' or 'kyc' in request.path %}active{% endif %}">
                <i class="fas fa-cog"></i> Settings
            </a>

            {% if user.is_staff %}
            <div class="nav-section">Admin</div>
            <a href="/admin/" class="nav-item" style="color: var(--gold);">
                <i class="fas fa-shield-alt"></i> Admin Panel
            </a>
            {% endif %}

            <div class="nav-section"></div>
            <a href="{% url 'accounts:logout' %}" class="nav-item" style="color: var(--error);">
                <i class="fas fa-sign-out-alt"></i> Logout
            </a>
            {% else %}
            <div class="nav-section">Account</div>
            <a href="{% url 'accounts:login' %}" class="nav-item">
                <i class="fas fa-sign-in-alt"></i> Login
            </a>
            <a href="{% url 'accounts:signup' %}" class="nav-item" style="background: linear-gradient(135deg, rgba(0,212,170,0.15), rgba(0,212,170,0.1)); border-left: 3px solid var(--success);">
                <i class="fas fa-user-plus" style="color: var(--success);"></i> <span style="color: var(--success);">Sign Up</span>
            </a>
            {% endif %}
        </nav>
    </aside>

    <!-- Main Content -->
    <main class="main-content">
        <!-- Messages -->
        {% if messages %}
        <div class="mb-3">
            {% for message in messages %}
            <div class="alert alert-{{ message.tags }} alert-floating alert-dismissible fade show" role="alert">
                <i class="fas fa-{% if message.tags == 'success' %}check-circle{% elif message.tags == 'error' or message.tags == 'danger' %}exclamation-circle{% elif message.tags == 'warning' %}exclamation-triangle{% else %}info-circle{% endif %} me-2"></i>
                {{ message }}
                <button type="button" class="btn-close" data-bs-dismiss="alert"></button>
            </div>
            {% endfor %}
        </div>
        {% endif %}

        {% block content %}{% endblock %}
    </main>

    <!-- Mobile Menu Button -->
    <button class="mobile-menu-btn" onclick="toggleSidebar()">
        <i class="fas fa-bars"></i>
    </button>

    <!-- Notification Toast Container -->
    <div class="toast-container position-fixed bottom-0 end-0 p-3" style="z-index: 2000;">
        <div id="notificationToast" class="toast hide" role="alert" aria-live="assertive" aria-atomic="true" style="background: var(--bg-dark); border: 1px solid var(--gold); color: white;">
            <div class="toast-header" style="background: var(--bg-dark); border-bottom: 1px solid var(--border-color); color: var(--gold);">
                <i class="fas fa-bell me-2"></i>
                <strong class="me-auto">New Notification</strong>
                <small id="toastTime">Just now</small>
                <button type="button" class="btn-close btn-close-white" data-bs-dismiss="toast" aria-label="Close"></button>
            </div>
            <div class="toast-body">
                <p id="toastMessage" class="mb-2"></p>
                <a id="toastAction" href="#" class="btn btn-gold btn-sm w-100">View Details</a>
            </div>
        </div>
    </div>

    <!-- Scripts -->
    <script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js"></script>
    <script>
        function toggleSidebar() {
            document.getElementById('sidebar').classList.toggle('active');
            document.getElementById('sidebarOverlay').classList.toggle('active');
        }

        document.getElementById('sidebarOverlay').addEventListener('click', toggleSidebar);

        // Close sidebar when clicking a nav item on mobile
        document.querySelectorAll('.nav-item').forEach(item => {
            item.addEventListener('click', () => {
                if (window.innerWidth < 992) {
                    toggleSidebar();
                }
            });
        });
    </script>

    <!-- Tawk.to Chat Widget -->
    <script type="text/javascript">
    var Tawk_API=Tawk_API||{}, Tawk_LoadStart=new Date();

    // Open live chat function
    function openLiveChat() {
        if (typeof Tawk_API !== 'undefined' && Tawk_API.maximize) {
            Tawk_API.maximize();
        } else {
            // Tawk not loaded yet, wait and retry
            var attempts = 0;
            var checkTawk = setInterval(function() {
                attempts++;
                if (typeof Tawk_API !== 'undefined' && Tawk_API.maximize) {
                    clearInterval(checkTawk);
                    Tawk_API.maximize();
                } else if (attempts > 10) {
                    clearInterval(checkTawk);
                    alert('Live chat is loading. Please try again in a moment.');
                }
            }, 500);
        }
    }

    // Load Tawk.to script
    (function(){
        var s1=document.createElement("script"),s0=document.getElementsByTagName("script")[0];
        s1.async=true;
        s1.src='https://embed.tawk.to/{{ TAWK_PROPERTY_ID|default:"69c1f2a729e9681c3d64de5d" }}/{{ TAWK_WIDGET_ID|default:"1jkepnodo" }}';
        s1.charset='UTF-8';
        s1.setAttribute('crossorigin','*');
        s0.parentNode.insertBefore(s1,s0);
    })();

    // Auto-show welcome message after load
    Tawk_API.onLoad = function() {
        console.log('Tawk.to chat loaded successfully');
    };
    </script>

    <!-- PWA Service Worker Registration -->
    <script>
        if ('serviceWorker' in navigator) {
            window.addEventListener('load', function() {
                navigator.serviceWorker.register('/sw.js')
                    .then(function(registration) {
                        console.log('ServiceWorker registered:', registration.scope);
                    })
                    .catch(function(error) {
                        console.log('ServiceWorker failed:', error);
                    });
            });
        }
    </script>

    <!-- Form UX Improvements -->
    <link rel="stylesheet" href="{% static 'css/form-improvements.css' %}">
    <script src="{% static 'js/form-improvements.js' %}"></script>
    <script src="{% static 'js/notifications.js' %}"></script>

    {% block extra_js %}{% endblock %}
</body>
</html>

